1554 static void splitPredecessorsOfLoopExit(PHINode *PN, DominatorTree *DT,
1555                                         LoopInfo *LI, const Loop *CurLoop,
1556                                         LoopSafetyInfo *SafetyInfo,
1557                                         MemorySSAUpdater *MSSAU) {
